import{_ as a,o as s,c as e,R as t}from"./chunks/framework.107209bd.js";const y=JSON.parse('{"title":"路由中hash和history的区别与原理","description":"","frontmatter":{},"headers":[],"relativePath":"技术分享&记录/编程思想/1、路由中hash和history的区别与原理.md","filePath":"技术分享&记录/编程思想/1、路由中hash和history的区别与原理.md","lastUpdated":null}'),o={name:"技术分享&记录/编程思想/1、路由中hash和history的区别与原理.md"},h=t('<h1 id="路由中hash和history的区别与原理" tabindex="-1">路由中hash和history的区别与原理 <a class="header-anchor" href="#路由中hash和history的区别与原理" aria-label="Permalink to &quot;路由中hash和history的区别与原理&quot;">​</a></h1><p>使用vue-router或react-router-dom时，一般会有两个路由模式供开发人员选择，分别是hash和history</p><h2 id="hash" tabindex="-1">hash <a class="header-anchor" href="#hash" aria-label="Permalink to &quot;hash&quot;">​</a></h2><h3 id="样式" tabindex="-1">样式 <a class="header-anchor" href="#样式" aria-label="Permalink to &quot;样式&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">var</span><span style="color:#A6ACCD;"> t </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> https:</span><span style="color:#676E95;font-style:italic;">//www.fam.tjfy.com/#/addAssets</span></span></code></pre></div><p>路由地址栏上会有 &quot;#&quot;</p><h3 id="原理" tabindex="-1">原理 <a class="header-anchor" href="#原理" aria-label="Permalink to &quot;原理&quot;">​</a></h3><p>基于<code>location.hash</code>实现，<code>location.hash</code>的值就是URL中<code>#</code>后面的内容</p><p>其原理是使用<code>hashchange</code>事件监听#后面内容的变化来发起请求进行局部更新</p><h3 id="触发hashchange事件" tabindex="-1">触发hashchange事件 <a class="header-anchor" href="#触发hashchange事件" aria-label="Permalink to &quot;触发hashchange事件&quot;">​</a></h3><ul><li>浏览器前进后退改变URL</li><li>a标签改变URL</li><li>window.location改变URL</li></ul><h2 id="history" tabindex="-1">history <a class="header-anchor" href="#history" aria-label="Permalink to &quot;history&quot;">​</a></h2><h3 id="样式-1" tabindex="-1">样式 <a class="header-anchor" href="#样式-1" aria-label="Permalink to &quot;样式&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">var</span><span style="color:#A6ACCD;"> t </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> https:</span><span style="color:#676E95;font-style:italic;">//www.fam.tjfy.com/addAssets</span></span></code></pre></div><p>路由地址栏上没有&quot;#&quot;</p><h3 id="原理-1" tabindex="-1">原理 <a class="header-anchor" href="#原理-1" aria-label="Permalink to &quot;原理&quot;">​</a></h3><p>利用HTML5新特性<code>window.history</code>中的<code>pushState(state, title, url)</code>或<code>replaceState(state, title, url)</code>实现路由跳转(这两个方法改变URL不会引起页面刷新)</p><h2 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h2><ul><li>样式上存在差别，一个带#，一个不带</li><li>兼容性存在差别，history为html5新特性兼容性不如hash模式</li><li>history模式需要后端进行额外配置，否则会出现刷新白屏 原因：页面刷新时，浏览器会向服务器发送此地址的请求，但对应文件资源不存在，所以会报404</li></ul>',19),l=[h];function r(i,n,c,d,p,u){return s(),e("div",null,l)}const m=a(o,[["render",r]]);export{y as __pageData,m as default};
